SELECT p.id, p.user_id, p.content, p.image_url, p.created_at, p.updated_at, u.username, u.display_name, u.avatar_url, p.like_count, p.comment_count, (SELECT EXISTS( SELECT 1 FROM post_likes pl WHERE pl.post_id = p.id AND pl.user_id = #{currentUserId} )) AS liked_by_current_user FROM posts p JOIN users u ON p.user_id = u.id
WHERE p.id < #{cursor}
ORDER BY p.id DESC LIMIT #{limit}

SELECT p.id, p.user_id, p.content, p.image_url, p.created_at, p.updated_at,
       u.username, u.display_name, u.avatar_url,
       p.like_count,
       p.comment_count,
       (SELECT EXISTS(
           SELECT 1 FROM post_likes pl
           WHERE pl.post_id = p.id
             AND pl.user_id = #{currentUserId}
       )) AS liked_by_current_user
FROM posts p
JOIN users u ON p.user_id = u.id
JOIN user_follows uf ON uf.following_id = p.user_id AND uf.follower_id = #{currentUserId}

    WHERE p.id < #{cursor}

ORDER BY p.id DESC
LIMIT #{limit}

SELECT p.id, p.user_id, p.content, p.image_url, p.created_at, p.updated_at,
       u.username, u.display_name, u.avatar_url,
       p.like_count,
       p.comment_count,
       (SELECT EXISTS(
           SELECT 1 FROM post_likes pl
           WHERE pl.post_id = p.id
             AND pl.user_id = #{currentUserId}
       )) AS liked_by_current_user
FROM posts p
JOIN users u ON p.user_id = u.id
WHERE p.user_id = #{userId}

    AND p.id < #{cursor}

ORDER BY p.id DESC
LIMIT #{limit}
